import { AppEvent, EventFilter } from './types';

export function validateEvent(input: Partial<AppEvent>): input is AppEvent {
  return Boolean(
    input.id &&
      input.type &&
      input.source &&
      input.message &&
      input.createdAt
  );
}

export function matchesFilter(event: AppEvent, filter: EventFilter): boolean {
  if (filter.type && event.type !== filter.type) return false;
  if (filter.source && event.source !== filter.source) return false;

  if (filter.search) {
    const q = filter.search.toLowerCase();
    const haystack = `${event.type} ${event.source} ${event.message}`.toLowerCase();
    if (!haystack.includes(q)) return false;
  }

  return true;
}

