import { AppEvent, EventFilter, matchesFilter } from '@monorepo/core';

const events: AppEvent[] = [];

export async function listEvents(filter: EventFilter = {}): Promise<AppEvent[]> {
  return events.filter((event) => matchesFilter(event, filter));
}

export async function createEvent(event: AppEvent): Promise<AppEvent> {
  events.push(event);
  return event;
}

import { Request, Response } from 'express';
import { AppEvent, EventFilter, validateEvent } from '@monorepo/core';
import { createEvent, listEvents } from '../db/events';

export async function listEventsHandler(req: Request, res: Response) {
  const filter: EventFilter = {
    type: typeof req.query.type === 'string' ? req.query.type : undefined,
    source: typeof req.query.source === 'string' ? req.query.source : undefined,
    search: typeof req.query.search === 'string' ? req.query.search : undefined
  };

  const events = await listEvents(filter);
  res.json({ data: events });
}

export async function createEventHandler(req: Request, res: Response) {
  const payload = req.body as Partial<AppEvent>;

  if (!validateEvent(payload)) {
    res.status(400).json({ error: 'Invalid event payload' });
    return;
  }

  const event = await createEvent(payload);
  res.status(201).json({ data: event });
}

