import React from 'react';
import { AppEvent } from '@monorepo/core';
import { Card } from './Card';

interface EventCardProps {
  event: AppEvent;
}

export function EventCard({ event }: EventCardProps) {
  return (
    <Card title={`${event.type} · ${event.source}`}>
      <p>{event.message}</p>
      <small>{new Date(event.createdAt).toLocaleString()}</small>
    </Card>
  );
}

import React from 'react';
import { AppEvent } from '@monorepo/core';
import { useQuery } from '../hooks/useQuery';
import { EventCard } from './EventCard';

interface EventListProps {
  endpoint?: string;
}

export function EventList({ endpoint = '/events' }: EventListProps) {
  const { data } = useQuery<AppEvent[]>(endpoint);

  if (!data) return <p>Loading events...</p>;
  if (data.length === 0) return <p>No events found.</p>;

  return (
    <div>
      {data.map((event) => (
        <EventCard key={event.id} event={event} />
      ))}
    </div>
  );
}

